// Validate Input v4.0 - Standard Contract Pattern
const body = $input.first().json.body || $input.first().json;

// Validación de campos requeridos (PRE-validation)
const required = ['provider_id', 'service_id', 'start_time'];
for (const field of required) {
  if (!body[field]) {
    return [{ json: { 
      success: false, 
      error_code: 'MISSING_FIELD', 
      error_message: `Missing required field: ${field}`,
      data: null,
      _meta: { source: 'WF2_v4', timestamp: new Date().toISOString() }
    }}];
  }
}

// Parsear y validar tipos
const provider_id = parseInt(body.provider_id, 10);
const service_id = parseInt(body.service_id, 10);
const start_time = body.start_time;

if (isNaN(provider_id) || isNaN(service_id) || !start_time) {
  return [{ json: { 
    success: false, 
    error_code: 'INVALID_TYPE', 
    error_message: 'provider_id, service_id must be numeric, start_time must be ISO string',
    data: null,
    _meta: { source: 'WF2_v4', timestamp: new Date().toISOString() }
  }}];
}

// Calcular end_time
const duration = parseInt(body.duration_minutes || 60, 10);
const startDate = new Date(start_time);
const endDate = new Date(startDate.getTime() + duration * 60000);

// Generar idempotency_key determinístico
const cleanTime = String(start_time).replace(/[^0-9]/g, '');
const idempotency_key = `booking_${provider_id}_${service_id}_${cleanTime}_${body.customer_id || body.chat_id || 'anon'}`;

// Sanitizar string (max 255 chars)
const sanitizedKey = idempotency_key.substring(0, 255);

// Construir contexto
const ctx = {
  provider_id,
  service_id,
  start_time,
  end_time: endDate.toISOString(),
  duration_minutes: duration,
  user_id: parseInt(body.user_id || 0, 10),
  customer_id: body.customer_id || null,
  chat_id: body.chat_id || null,
  event_title: body.event_title || 'Appointment',
  idempotency_key: sanitizedKey,
  _meta: {
    source: 'WF2_Booking_Orchestrator_v4',
    version: '4.0.0-internal',
    timestamp: new Date().toISOString()
  }
};

return [{ json: { ctx } }];

// Process Idempotency Check
const items = $input.all();
const ctx = $('Validate Input').first().json.ctx;

// Verificar si hay booking existente
const dup = (items.length > 0 && items[0].json.booking_id) ? items[0].json : null;

if (dup) {
  // Booking ya existe - retornar existente
  return [{ json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      booking_id: dup.booking_id,
      status: dup.status,
      gcal_event_id: dup.gcal_event_id,
      is_duplicate: true,
      message: 'Booking already exists (idempotent retry)'
    },
    _meta: ctx._meta
  }}];
}

// No es duplicado - continuar con flujo
return [{ json: { ctx, is_duplicate: false } }];

// Acquire Lock v4.0 - Internal DB Lock
const ctx = $input.first().json.ctx;
const lock_key = `lock_${ctx.provider_id}_${ctx.start_time}`;
const owner_token = ctx.idempotency_key;

return [{ json: {
  ctx,
  lock_key,
  owner_token,
  lock_query: `INSERT INTO booking_locks (provider_id, start_time, lock_key, owner_token, expires_at, created_at) 
    VALUES (${ctx.provider_id}, '${ctx.start_time}'::timestamptz, '${lock_key}', '${owner_token}', NOW() + INTERVAL '5 minutes', NOW()) 
    ON CONFLICT (lock_key) DO UPDATE SET expires_at = NOW() + INTERVAL '5 minutes', updated_at = NOW() 
    WHERE booking_locks.expires_at < NOW() 
    RETURNING id, owner_token;`
}}];

// Process Lock Result
const items = $input.all();
const ctx = $('Build Lock Query').first().json.ctx;
const lock_key = $('Build Lock Query').first().json.lock_key;
const owner_token = $('Build Lock Query').first().json.owner_token;

// Verificar si se adquirió el lock
const lock_acquired = (items.length > 0 && items[0].json.id) ? true : false;

if (!lock_acquired) {
  // Lock denegado - slot ya está reservado
  return [{ json: {
    success: false,
    error_code: 'LOCK_DENIED',
    error_message: 'Slot already booked by another user',
    data: { lock_key },
    _meta: ctx._meta
  }}];
}

// Lock adquirido - continuar
return [{ json: { ctx, lock_key, owner_token, lock_acquired } }];

// Check Circuit Breaker v4.0 - Internal DB Check
const ctx = $input.first().json.ctx;
const lock_key = $input.first().json.lock_key;
const owner_token = $input.first().json.owner_token;

return [{ json: {
  ctx,
  lock_key,
  owner_token,
  cb_query: `SELECT allowed, failure_count, last_failure_at FROM circuit_breaker WHERE service_id = 'google_calendar' LIMIT 1;`
}}];

// Process Circuit Breaker Result
const items = $input.all();
const ctx = $('Build CB Query').first().json.ctx;
const lock_key = $('Build CB Query').first().json.lock_key;
const owner_token = $('Build CB Query').first().json.owner_token;

// Verificar estado del circuit breaker
const cb_row = (items.length > 0 && items[0].json) ? items[0].json : null;
const cb_allowed = cb_row && cb_row.allowed === true;

if (!cb_allowed) {
  // Circuit breaker abierto - GCal no disponible
  return [{ json: {
    success: false,
    error_code: 'CIRCUIT_BREAKER_OPEN',
    error_message: 'Google Calendar service is temporarily unavailable',
    data: { 
      service: 'google_calendar',
      failure_count: cb_row?.failure_count || 0
    },
    _meta: ctx._meta
  }}];
}

// Circuit breaker cerrado - continuar
return [{ json: { ctx, lock_key, owner_token, cb_allowed: true } }];

// Check Availability v4.0 - Internal DB Check
const ctx = $input.first().json.ctx;
const lock_key = $input.first().json.lock_key;
const owner_token = $input.first().json.owner_token;

return [{ json: {
  ctx,
  lock_key,
  owner_token,
  avail_query: `SELECT COUNT(*) as count FROM bookings WHERE provider_id = ${ctx.provider_id} AND service_id = ${ctx.service_id} AND start_time = '${ctx.start_time}'::timestamptz AND status = 'CONFIRMED';`
}}];

// Process Availability Result
const items = $input.all();
const ctx = $('Build Avail Query').first().json.ctx;
const lock_key = $('Build Avail Query').first().json.lock_key;
const owner_token = $('Build Avail Query').first().json.owner_token;

// Verificar disponibilidad
const avail_row = (items.length > 0 && items[0].json) ? items[0].json : null;
const avail_count = parseInt(avail_row?.count || '0', 10);
const is_available = avail_count === 0;

if (!is_available) {
  // No hay disponibilidad - slot ya reservado
  return [{ json: {
    success: false,
    error_code: 'NO_AVAILABILITY',
    error_message: 'No availability found for requested time slot',
    data: { 
      provider_id: ctx.provider_id,
      service_id: ctx.service_id,
      start_time: ctx.start_time
    },
    _meta: ctx._meta
  }}];
}

// Hay disponibilidad - continuar
return [{ json: { ctx, lock_key, owner_token, is_available: true } }];

// Process GCal Result
const items = $input.all();
const ctx = $('Create GCal Event').first().json.ctx;
const lock_key = $('Create GCal Event').first().json.lock_key;
const owner_token = $('Create GCal Event').first().json.owner_token;

// Verificar si se creó el evento GCal
const gcal_row = (items.length > 0 && items[0].json) ? items[0].json : null;
const gcal_event_id = gcal_row?.id || null;
const gcal_success = !!gcal_event_id;

if (!gcal_success) {
  // Error creando GCal - liberar lock y retornar error
  return [{ json: {
    success: false,
    error_code: 'GCAL_ERROR',
    error_message: gcal_row?.message || 'Failed to create Google Calendar event',
    data: { service: 'google_calendar' },
    _meta: ctx._meta,
    needs_lock_release: true,
    lock_key,
    owner_token
  }}];
}

// GCal creado exitosamente - continuar
return [{ json: { ctx, lock_key, owner_token, gcal_event_id, gcal_success: true } }];

// Process Booking Result
const items = $input.all();
const ctx = $('Create Booking').first().json.ctx;
const lock_key = $('Create Booking').first().json.lock_key;
const owner_token = $('Create Booking').first().json.owner_token;
const gcal_event_id = $('Create Booking').first().json.gcal_event_id;

// Verificar si se creó el booking
const booking_row = (items.length > 0 && items[0].json) ? items[0].json : null;
const booking_id = booking_row?.id || null;
const booking_success = !!booking_id;

if (!booking_success) {
  // Error creando booking - necesita rollback de GCal
  return [{ json: {
    success: false,
    error_code: 'DB_ERROR',
    error_message: 'Failed to create booking in database',
    data: { 
      gcal_event_id,
      needs_rollback: true,
      needs_lock_release: true
    },
    _meta: ctx._meta,
    lock_key,
    owner_token
  }}];
}

// Booking creado exitosamente - continuar
return [{ json: { 
  ctx, 
  lock_key, 
  owner_token, 
  gcal_event_id, 
  booking_id, 
  booking_success: true 
}}];

// Standard Contract Output v4.0 - Booking Success
const ctx = $('Process Booking').first().json.ctx;
const booking_id = $('Process Booking').first().json.booking_id;
const gcal_event_id = $('Process Booking').first().json.gcal_event_id;

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    booking_id: booking_id,
    idempotency_key: ctx.idempotency_key,
    provider_id: ctx.provider_id,
    service_id: ctx.service_id,
    start_time: ctx.start_time,
    end_time: ctx.end_time,
    status: 'CONFIRMED',
    gcal_event_id: gcal_event_id,
    is_duplicate: false
  },
  _meta: {
    source: 'WF2_Booking_Orchestrator_v4',
    timestamp: new Date().toISOString(),
    version: '4.0.0-internal'
  }
}}];

// Error Output Helper v4.0
const input = $input.first().json;
return [{ json: {
  success: input.success || false,
  error_code: input.error_code || 'UNKNOWN_ERROR',
  error_message: input.error_message || 'An unexpected error occurred',
  data: input.data || null,
  _meta: input._meta || {
    source: 'WF2_Booking_Orchestrator_v4',
    timestamp: new Date().toISOString(),
    version: '4.0.0-internal'
  }
}}];
